INSERT INTO organization_accounts (organization_id, account_id)
SELECT o.id, a.id FROM membership m JOIN organizations o ON o.tag = m.tag JOIN accounts a ON a.email = m.email
ON CONFLICT DO NOTHING;

CREATE OR REPLACE FUNCTION pg_temp.detailit_course(p_org_tag text, p_title text, p_description text, p_owner_email text)
RETURNS bigint AS $$
DECLARE v_course_id bigint; v_org_id bigint; v_owner_id bigint;
BEGIN
    SELECT id INTO v_org_id FROM organizations WHERE tag = p_org_tag;
    SELECT id INTO v_owner_id FROM accounts WHERE email = p_owner_email;
    SELECT id INTO v_course_id FROM courses WHERE title = p_title AND organization_id = v_org_id LIMIT 1;
    IF v_course_id IS NULL THEN
        INSERT INTO courses (title, description, owner, organization_id) VALUES (p_title, p_description, v_owner_id, v_org_id) RETURNING id INTO v_course_id;
    ELSE
        UPDATE courses SET description = p_description, owner = v_owner_id WHERE id = v_course_id;
    END IF;
    RETURN v_course_id;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION pg_temp.detailit_module(p_course_id bigint, p_index int, p_title text)
RETURNS bigint AS $$
DECLARE v_module_id bigint;
BEGIN
    SELECT m.id INTO v_module_id FROM modules m JOIN course_modules cm ON cm.module_id = m.id WHERE cm.course_id = p_course_id AND m.title = p_title LIMIT 1;
    IF v_module_id IS NULL THEN
        INSERT INTO modules (title) VALUES (p_title) RETURNING id INTO v_module_id;
        INSERT INTO course_modules (course_id, module_id, index) VALUES (p_course_id, v_module_id, p_index) ON CONFLICT DO NOTHING;
    ELSE
        UPDATE course_modules SET index = p_index WHERE course_id = p_course_id AND module_id = v_module_id;
    END IF;
    RETURN v_module_id;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION pg_temp.detailit_slide(p_module_id bigint, p_index int, p_title text, p_description text, p_type slide_variation, p_payload jsonb)
RETURNS bigint AS $$
DECLARE v_slide_id bigint;
BEGIN
    SELECT s.id INTO v_slide_id FROM slides s JOIN module_slides ms ON ms.slide_id = s.id WHERE ms.module_id = p_module_id AND s.title = p_title LIMIT 1;
    IF v_slide_id IS NULL THEN
        INSERT INTO slides (title, description, slide_type, payload) VALUES (p_title, p_description, p_type, p_payload) RETURNING id INTO v_slide_id;
        INSERT INTO module_slides (module_id, slide_id, index) VALUES (p_module_id, v_slide_id, p_index) ON CONFLICT DO NOTHING;
    ELSE
        UPDATE slides SET description = p_description, slide_type = p_type, payload = p_payload WHERE id = v_slide_id;
        UPDATE module_slides SET index = p_index WHERE module_id = p_module_id AND slide_id = v_slide_id;
    END IF;
    RETURN v_slide_id;
END;
$$ LANGUAGE plpgsql;

DO $detailit$
DECLARE c_id bigint; m_id bigint;
BEGIN
    c_id := pg_temp.detailit_course('detailit', 'Безопасность и вводный инструктаж на производстве', 'Большой практический курс ООО "ДетаЛит" для производственных подразделений по профилю ОКВЭД 29.31. Тема: Безопасность и вводный инструктаж на производстве. В курсе минимум 5 модулей, учебные файлы, видеоразборы, контрольные вопросы и практические чек-листы для допуска сотрудника.', 'director@detailit.ru');
    m_id := pg_temp.detailit_module(c_id, 1, 'Вводный инструктаж');
    PERFORM pg_temp.detailit_slide(m_id, 1, 'Вводный инструктаж: цель и результат', 'Теория и практический смысл раздела курса Безопасность и вводный инструктаж на производстве', 'TEXT', $json${"content":"# Вводный инструктаж\n\nРаздел курса «Безопасность и вводный инструктаж на производстве» разбирает производственную ситуацию ООО \"ДетаЛит\". Сотрудник изучает цель операции, границы ответственности, признаки отклонений и порядок записи результата.\n\n**Ключевые действия:**\n\n- сверить задание, маршрутную карту и актуальную версию документа;\n- проверить рабочее место, материалы, инструмент и средства защиты;\n- выполнить операцию по технологической последовательности;\n- остановить передачу изделия при спорном качестве;\n- зафиксировать результат так, чтобы партию можно было восстановить по истории.\n\nПрактический итог раздела: сотрудник должен объяснить, что он делает, зачем это влияет на изделие автомобиля и какие данные нужно оставить после операции."}$json$::jsonb);
    PERFORM pg_temp.detailit_slide(m_id, 2, 'Вводный инструктаж: учебная схема или документ', 'Файл для изучения, повторения или очного инструктажа', 'FILE', $json${"filename":"harness-assembly.png","object_key":"course_files/detailit/harness-assembly.png","mime_type":"image/png"}$json$::jsonb);
    PERFORM pg_temp.detailit_slide(m_id, 3, 'Вводный инструктаж: видеоразбор', 'Видеоматериал для самостоятельного изучения', 'VIDEO_URL', $json${"videoUrl":"https://www.youtube.com/watch?v=OSUvXC1pACA"}$json$::jsonb);
    PERFORM pg_temp.detailit_slide(m_id, 4, 'Вводный инструктаж: чек-лист сотрудника', 'Практический порядок действий на рабочем месте', 'TEXT', $json${"content":"# Вводный инструктаж\n\nРаздел курса «Безопасность и вводный инструктаж на производстве» разбирает производственную ситуацию ООО \"ДетаЛит\". Сотрудник изучает цель операции, границы ответственности, признаки отклонений и порядок записи результата.\n\n**Ключевые действия:**\n\n- сверить задание, маршрутную карту и актуальную версию документа;\n- проверить рабочее место, материалы, инструмент и средства защиты;\n- выполнить операцию по технологической последовательности;\n- остановить передачу изделия при спорном качестве;\n- зафиксировать результат так, чтобы партию можно было восстановить по истории.\n\nПрактический итог раздела: сотрудник должен объяснить, что он делает, зачем это влияет на изделие автомобиля и какие данные нужно оставить после операции."}$json$::jsonb);
    PERFORM pg_temp.detailit_slide(m_id, 5, 'Вводный инструктаж: контрольный тест', 'Проверка понимания ключевого правила', 'TEST', $json${"question":"Что нужно сделать, если в разделе «Вводный инструктаж» обнаружено отклонение, влияющее на качество партии?","isMultiSelect":false,"output":2,"options":[{"id":1,"text":"Передать изделие дальше и вернуться к вопросу позже","isCorrect":false},{"id":2,"text":"Остановить передачу, изолировать спорную единицу и сообщить ответственному","isCorrect":true},{"id":3,"text":"Исправить запись без уведомления мастера","isCorrect":false}]}$json$::jsonb);
    PERFORM pg_temp.detailit_slide(m_id, 6, 'Вводный инструктаж: типовые ошибки и допуск', 'Закрепление темы перед переходом к следующему модулю', 'TEXT', $json${"content":"# Вводный инструктаж\n\nРаздел курса «Безопасность и вводный инструктаж на производстве» разбирает производственную ситуацию ООО \"ДетаЛит\". Сотрудник изучает цель операции, границы ответственности, признаки отклонений и порядок записи результата.\n\n**Ключевые действия:**\n\n- сверить задание, маршрутную карту и актуальную версию документа;\n- проверить рабочее место, материалы, инструмент и средства защиты;\n- выполнить операцию по технологической последовательности;\n- остановить передачу изделия при спорном качестве;\n- зафиксировать результат так, чтобы партию можно было восстановить по истории.\n\nПрактический итог раздела: сотрудник должен объяснить, что он делает, зачем это влияет на изделие автомобиля и какие данные нужно оставить после операции."}$json$::jsonb);
